import { purchaseModelCode as purchaseModelCodeEnum } from '@otovo/shared/cloudEnums';
import { PANELS_INSTALLED_PER_DAY } from '@otovo/shared/constants/cloudConstants';
import {
  Cloud$Interest,
  Cloud$PackageOptionBattery,
  Cloud$PackageOptionPV,
  Cloud$Package,
} from '@otovo/shared/types/cloudApi';
import {
  Cloud$PackageSize,
  Cloud$ProductName,
} from '@otovo/shared/types/cloudEnums';
import { checkIsLeasingInPurchaseModels } from './checkIsLeasingInPurchaseModels';

export const estimateInstallationDuration = (amountOfPanels: number): number =>
  Math.ceil(amountOfPanels / PANELS_INSTALLED_PER_DAY);

export const getPanelCapacityFromPackage = (
  solarPackage: Cloud$Package,
): number => solarPackage.price.equipment.panels.nominal_panel_power;

export const isBatteryPackage = (pkg: Cloud$Package): boolean => {
  return !!pkg.price.equipment.batteries.length;
};
export const isEvChargerPackage = (pkg: Cloud$Package): boolean => {
  return !!pkg.price.equipment.ev_chargers.length;
};

export const hasMultiplePackages = (interest: Cloud$Interest): boolean => {
  return interest.products.flatMap((product) => product.packages).length > 1;
};

export const hasBatteryPackage = (interest: Cloud$Interest) => {
  return interest.products
    .flatMap((product) => product.packages)
    .some((pkg) => isBatteryPackage(pkg));
};
export const hasEvChargerPackage = (interest: Cloud$Interest) => {
  return interest.products
    .flatMap((product) => product.packages)
    .some((pkg) => isEvChargerPackage(pkg));
};

const isEquivalentPackage = (
  pkg1: Cloud$Package,
  pkg2: Cloud$Package,
): boolean =>
  pkg1.product_name === pkg2.product_name &&
  pkg1.package_size === pkg2.package_size;

/**
 * This checks if the package changes (e.g. standard_small -> standard_large)
 * going from a PV package to a PV + battery package.
 */
export const isPackageUpgraded = ({
  selectedPackage,
  previousPackage,
}: {
  selectedPackage: Cloud$Package;
  previousPackage: Cloud$Package;
}): boolean => {
  return (
    !isBatteryPackage(previousPackage) &&
    isBatteryPackage(selectedPackage) &&
    !isEquivalentPackage(selectedPackage, previousPackage)
  );
};

/**
 * Returns all packages in the interest fulfilling the battery requirement.
 * Packages are sorted by gross price, from lowest to highest.
 */
const getSortedPackagesByPrice = (
  interest: Cloud$Interest,
  withBattery: boolean,
  withEvCharger: boolean,
): Array<Cloud$Package> => {
  return interest.products
    .slice()
    .flatMap((product) => product.packages)
    .filter((pkg: Cloud$Package) => isBatteryPackage(pkg) === withBattery)
    .filter((pkg: Cloud$Package) => isEvChargerPackage(pkg) === withEvCharger)
    .sort(
      (pkg1, pkg2) =>
        pkg1.price.financing_options[0].total_gross_price -
        pkg2.price.financing_options[0].total_gross_price,
    );
};
/**
 * Given the selected package, this function attempts to find the equivalent
 * package (same package label, e.g. standard_small) fulfilling the hardware
 * requirement, using the following search order:
 *
 *   1) Package fulfilling the hardware requrement with the same product and size
 *      as the selected package.
 *   2) Cheapest package in the interest fulfilling the hardware requirement.
 *
 * Returns null if no package in the interest fulfills the hardware requirement.
 */

export const getClosestPackage = ({
  interest,
  selectedPackage,
  withBattery,
  withEvCharger,
}: {
  interest: Cloud$Interest;
  selectedPackage: Cloud$Package;
  withBattery?: boolean;
  withEvCharger?: boolean;
}): Cloud$Package | null => {
  const availablePackages = getSortedPackagesByPrice(
    interest,
    !!withBattery,
    !!withEvCharger,
  );
  const equivalentPackage = availablePackages.find((pkg: Cloud$Package) =>
    isEquivalentPackage(pkg, selectedPackage),
  );

  return equivalentPackage || availablePackages[0] || null;
};

export const packageHas3PurchaseModels = (
  selectedPackage: Cloud$Package,
): boolean => {
  const isLeasingInPurchaseModels = checkIsLeasingInPurchaseModels(
    selectedPackage.price.financing_options,
  );
  const { financing_options: purchaseModels } = selectedPackage.price;
  const selectorPurchaseModelCodes = purchaseModels.map(
    (purchaseModel) => purchaseModel.purchase_model_code,
  );
  let has3PurchaseModels: boolean;

  if (!isLeasingInPurchaseModels) {
    has3PurchaseModels = false;
    const leasingIndex = purchaseModels.findIndex(
      (purchaseModel) =>
        purchaseModel.purchase_model_code === purchaseModelCodeEnum.LEASING,
    );
    if (leasingIndex !== -1) {
      selectorPurchaseModelCodes.splice(leasingIndex, 1);
    }
  } else {
    has3PurchaseModels = purchaseModels.length === 3;

    if (has3PurchaseModels) {
      const loanIndex = purchaseModels.findIndex(
        (purchaseModel) =>
          purchaseModel.purchase_model_code === purchaseModelCodeEnum.LOAN,
      );
      if (loanIndex !== -1) {
        selectorPurchaseModelCodes.splice(loanIndex, 1);
      }
    }
  }
  return has3PurchaseModels;
};

export const getProductOptions = (
  selectedShoppingCartPackage: Cloud$Package,
  pvPackages: Cloud$PackageOptionPV[],
) => {
  const products: Cloud$ProductName[] = ['standard', 'premium', 'tier3'];
  const availableProducts = pvPackages.map((p) => p.pv_product_name);

  const productOptions = products.map((product) => {
    const pvPackage = pvPackages.find((p) => p.pv_product_name === product);
    return {
      name: product,
      nominalPanelPower: pvPackage ? pvPackage.nominal_panel_power : null,
      isAvailable: availableProducts.includes(product),
      isSelected: selectedShoppingCartPackage.product_name === product,
    };
  });

  return productOptions;
};

export const getPackageSizeOptions = (
  selectedShoppingCartPackage: Cloud$Package,
  pvPackages: Cloud$PackageOptionPV[],
) => {
  const packageSizes: Cloud$PackageSize[] = ['small', 'economic', 'large'];
  const nonCompatiblePackageSizes = pvPackages
    .filter(
      (p) => p.pv_product_name === selectedShoppingCartPackage.product_name,
    )
    .map((p) => p.pv_package_size);
  const compatiblePackageSizes = pvPackages
    .filter(
      (p) => p.pv_product_name === selectedShoppingCartPackage.product_name,
    )
    .filter(
      (p) => p.with_battery === isBatteryPackage(selectedShoppingCartPackage),
    )
    .filter(
      (p) =>
        p.with_ev_charger === isEvChargerPackage(selectedShoppingCartPackage),
    )
    .map((p) => p.pv_package_size);
  return packageSizes.map((packageSize) => ({
    packageSize,
    isNonCompatible: !nonCompatiblePackageSizes.includes(packageSize),
    isDisabled: !compatiblePackageSizes.includes(packageSize),
    isSelected: selectedShoppingCartPackage.package_size === packageSize,
    numberOfPanels: pvPackages.find((p) => p.pv_package_size === packageSize)
      ?.number_of_panels,
    nominalSystemPower:
      pvPackages.find((p) => p.pv_package_size === packageSize)
        ?.nominal_system_power / 1000,
  }));
};

export const getBatteryCapacityRange = (
  packageSize: Cloud$PackageSize,
  availableBatteryPackages: Cloud$PackageOptionBattery[],
) => {
  const packageSizeToCapacity = new Map(
    availableBatteryPackages.map((pkg) => [
      pkg.battery_package_size,
      pkg.minimum_battery_capacity,
    ]),
  );
  const availablePackageSizes: Cloud$PackageSize[] =
    availableBatteryPackages.map((p) => p.battery_package_size);
  switch (packageSize) {
    case 'small':
      if (!availablePackageSizes.includes('economic')) {
        return {
          minCapacity: packageSizeToCapacity.get('small'),
          maxCapacity: packageSizeToCapacity.get('large'),
        };
      }
      return {
        minCapacity: packageSizeToCapacity.get('small'),
        maxCapacity: packageSizeToCapacity.get('economic'),
      };
    case 'economic':
      if (!availablePackageSizes.includes('large')) {
        return {
          minCapacity: packageSizeToCapacity.get('economic'),
          maxCapacity: null,
        };
      }
      return {
        minCapacity: packageSizeToCapacity.get('economic'),
        maxCapacity: packageSizeToCapacity.get('large'),
      };
    case 'large':
      return {
        minCapacity: packageSizeToCapacity.get('large'),
        maxCapacity: null,
      };
    default:
      return {
        minCapacity: null,
        maxCapacity: null,
      };
  }
};
