import cx from 'classnames';

type ProductSwitchOption = {
  key: string;
  label: React.ReactNode;
  labelSecondary?: React.ReactNode;
  value: string;
  onSelect: (e: React.ChangeEvent<HTMLInputElement>) => void;
};

type Props = {
  options: ProductSwitchOption[];
  testIdPrefix: string;
  name: string;
  defaultValue: string;
};

export default function ProductSwitch({
  options,
  testIdPrefix = '',
  name,
  defaultValue,
}: Props) {
  return (
    <div
      className="flex overflow-hidden rounded-lg border border-[var(--bg-300)] bg-[var(--bg-100)] p-1"
      role="radiogroup"
    >
      {options.map((option) => (
        <div key={option.key} className="flex-1">
          <input
            id={option.key}
            type="radio"
            name={name}
            value={option.value}
            defaultChecked={option.value === defaultValue}
            onChange={option.onSelect}
            className="peer sr-only"
            data-testid={testIdPrefix + option.key}
          />
          <label
            htmlFor={option.key}
            className={cx(
              'block h-full rounded-md',
              'cursor-pointer py-2 md:py-3',
              'peer-focus:ring-2 peer-focus:ring-digital peer-focus:ring-offset-1',
              'peer-checked:bg-[var(--bg-400)] peer-checked:text-white',
              'text-grey-60',
              'my-0 text-center text-sm font-semibold md:text-[18px]',
            )}
          >
            {option.label}
            {option.labelSecondary && (
              <span className="block text-sm font-normal">
                {option.labelSecondary}
              </span>
            )}
          </label>
        </div>
      ))}
    </div>
  );
}
